const should = require('should');
const expect = require('chai').expect;
const assert = require('chai').assert;
const PromiseFactory = require('logged-promise');
const async = require('async');

const ConfigHelper = require('../helpers/ConfigHelper');

const ModelFactory = require('../../index');

const config = require('../config');

const serviceInit = {
	requestId: "TEST-" + require('uuid/v1')(),
	currentUser: {
		organizationId: 1,
		userId: 1,
		username: 'test@corebit.tech'
	}
};

PromiseFactory.appStart(ConfigHelper.getLogger());

describe("Model Flow Tests", function () {
	this.timeout(150000);

	before((done) => {
		ModelFactory.appStart(ConfigHelper.getLogger(), config, (db) => {
			async.each(db, (model, cb) => {
				model.sync({force: true}).then(() => {
					cb(null);
				});
			}, () => {
				db.Blog.belongsTo(db.Organization, {foreignKey: 'organizationId', as: 'organization'});
				done();
			});
		});
	});

	after((done) => {
		ModelFactory.appStart(ConfigHelper.getLogger(), config, (db) => {
			async.each(db, (model, cb) => {
				model.drop().then(() => {
					cb(null);
				});
			}, done);
		});
	});


	it ('It checks include flow with model name which is not exists', (done) => {

		expect(() => {
			ModelFactory
				.init(serviceInit)
				.get('Blog')
				.findAll({
					include: ['Organization', 'Test']
				})
				.catch((err) => {
					console.error(err);
					throw err;
				});
		}).to.throw(Error, /optionSetIncludeModel: Test is not exists/);
		done();
	});

	it ('It checks include flow with model name which is null', (done) => {
		expect(() => {
			ModelFactory
				.init(serviceInit)
				.get('Blog')
				.findAll({
					include: [null, 'Test']
				});
		}).to.throw(Error, /optionSetIncludeModel: model is null or undefined/);

		done();
	});

});